using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes =
    [
        new()
        {
            Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
            Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
            Steps = ["Preheat oven to 475°F.", "Roll out dough on floured surface.", "Spread crushed tomatoes evenly.", "Add torn mozzarella pieces.", "Bake for 10-12 minutes.", "Top with fresh basil and drizzle olive oil."],
            AverageRating = 4.5, RatingCount = 12
        },
        new()
        {
            Id = 2, Title = "Chicken Tikka Masala", Category = "Indian",
            Ingredients = ["Chicken breast", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Garlic", "Ginger", "Rice"],
            Steps = ["Marinate chicken in yogurt and spices for 2 hours.", "Grill or pan-fry chicken until charred.", "Sauté garlic and ginger in butter.", "Add tomato sauce and simmer.", "Stir in cream and spices.", "Add chicken and serve over rice."],
            AverageRating = 4.8, RatingCount = 24
        },
        new()
        {
            Id = 3, Title = "Beef Tacos", Category = "Mexican",
            Ingredients = ["Ground beef", "Taco shells", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Taco seasoning"],
            Steps = ["Brown ground beef in a skillet.", "Add taco seasoning and water, simmer.", "Warm taco shells.", "Assemble with beef, lettuce, tomato, cheese.", "Top with sour cream."],
            AverageRating = 4.2, RatingCount = 8
        },
        new()
        {
            Id = 4, Title = "Pad Thai", Category = "Asian",
            Ingredients = ["Rice noodles", "Shrimp", "Eggs", "Bean sprouts", "Green onions", "Peanuts", "Lime", "Fish sauce", "Tamarind paste"],
            Steps = ["Soak rice noodles in warm water.", "Stir-fry shrimp until pink, set aside.", "Scramble eggs in the wok.", "Add noodles and sauce (fish sauce, tamarind, sugar).", "Toss with shrimp, bean sprouts, and green onions.", "Serve with crushed peanuts and lime wedge."],
            AverageRating = 4.6, RatingCount = 15
        },
        new()
        {
            Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts",
            Ingredients = ["Dark chocolate", "Butter", "Eggs", "Sugar", "Flour", "Vanilla extract"],
            Steps = ["Preheat oven to 425°F.", "Melt chocolate and butter together.", "Whisk eggs and sugar until thick.", "Fold chocolate mixture into eggs.", "Add flour and vanilla.", "Bake in greased ramekins for 12 minutes.", "Invert onto plates and serve immediately."],
            AverageRating = 4.9, RatingCount = 31
        },
        new()
        {
            Id = 6, Title = "Caesar Salad", Category = "Salads",
            Ingredients = ["Romaine lettuce", "Parmesan cheese", "Croutons", "Caesar dressing", "Lemon juice", "Anchovy paste"],
            Steps = ["Wash and chop romaine lettuce.", "Make dressing: whisk anchovy paste, lemon, garlic, and oil.", "Toss lettuce with dressing.", "Top with shaved parmesan and croutons."],
            AverageRating = 3.9, RatingCount = 6
        }
    ];

    private static readonly List<RecipeCategory> Categories =
    [
        new() { Name = "Italian", Description = "Pasta, pizza, and Mediterranean flavors", Icon = "🍕" },
        new() { Name = "Indian", Description = "Rich curries and aromatic spices", Icon = "🍛" },
        new() { Name = "Mexican", Description = "Bold flavors with fresh ingredients", Icon = "🌮" },
        new() { Name = "Asian", Description = "Stir-fries, noodles, and umami", Icon = "🍜" },
        new() { Name = "Desserts", Description = "Sweet treats and baked goods", Icon = "🍰" },
        new() { Name = "Salads", Description = "Fresh, healthy, and colorful", Icon = "🥗" }
    ];

    public List<RecipeCategory> GetCategories() => Categories;

    public List<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipeById(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is null) return;

        var totalStars = recipe.AverageRating * recipe.RatingCount + stars;
        recipe.RatingCount++;
        recipe.AverageRating = Math.Round(totalStars / recipe.RatingCount, 1);
    }

    public void SubmitRecipe(RecipeSubmission submission)
    {
        var newId = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(new Recipe
        {
            Id = newId,
            Title = submission.Title,
            Category = submission.Category,
            Ingredients = submission.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries).ToList(),
            Steps = submission.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries).ToList(),
            AverageRating = 0,
            RatingCount = 0
        });
    }
}

