@page "/"
@using RecipeCommunity.Services

<PageTitle>Recipe Community</PageTitle>

<div class="container">
    <div class="text-center my-4">
        <h1>🍳 Recipe Community</h1>
        <p class="lead">Discover and share delicious recipes from around the world</p>
    </div>

    <h2>Browse by Category</h2>
    <div class="row">
        @foreach (var category in _categories)
        {
            <div class="col-md-4 mb-4">
                <div class="card h-100">
                    <div class="card-body text-center">
                        <span class="display-4">@category.Icon</span>
                        <h5 class="card-title mt-2">@category.Name</h5>
                        <p class="card-text">@category.Description</p>
                        <a href="/category/@category.Name" class="btn btn-outline-primary">View Recipes</a>
                    </div>
                </div>
            </div>
        }
    </div>
</div>

@code {
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private List<RecipeCommunity.Models.RecipeCategory> _categories = [];

    protected override void OnInitialized()
    {
        _categories = RecipeService.GetCategories();
    }
}

@page "/category/{CategoryName}"
@using RecipeCommunity.Models
@using RecipeCommunity.Services

<PageTitle>@CategoryName Recipes</PageTitle>

<div class="container">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item active">@CategoryName</li>
        </ol>
    </nav>

    <h1>@CategoryName Recipes</h1>

    @if (_recipes.Count == 0)
    {
        <p>No recipes found in this category yet.</p>
    }
    else
    {
        <div class="row">
            @foreach (var recipe in _recipes)
            {
                <div class="col-md-6 mb-4">
                    <div class="card">
                        <div class="card-body">
                            <h5 class="card-title">@recipe.Title</h5>
                            <p class="card-text text-muted">
                                ⭐ @recipe.AverageRating.ToString("0.0") (@recipe.RatingCount ratings)
                            </p>
                            <a href="/recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private List<Recipe> _recipes = [];

    protected override void OnInitialized()
    {
        _recipes = RecipeService.GetRecipesByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeCommunity.Models
@using RecipeCommunity.Services
@rendermode InteractiveServer

<PageTitle>@(_recipe?.Title ?? "Recipe")</PageTitle>

<div class="container">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            @if (_recipe is not null)
            {
                <li class="breadcrumb-item"><a href="/category/@_recipe.Category">@_recipe.Category</a></li>
                <li class="breadcrumb-item active">@_recipe.Title</li>
            }
        </ol>
    </nav>

    @if (_recipe is null)
    {
        <p>Recipe not found.</p>
    }
    else
    {
        <h1>@_recipe.Title</h1>

        <RecipeCommunity.Components.Shared.StarRating
            RecipeId="@_recipe.Id"
            AverageRating="@_recipe.AverageRating"
            RatingCount="@_recipe.RatingCount"
            OnRated="HandleRating" />

        <h3 class="mt-4">Ingredients</h3>
        <ul class="list-group mb-4">
            @foreach (var ingredient in _recipe.Ingredients)
            {
                <li class="list-group-item">@ingredient</li>
            }
        </ul>

        <h3>Steps</h3>
        <ol class="list-group list-group-numbered mb-4">
            @foreach (var step in _recipe.Steps)
            {
                <li class="list-group-item">@step</li>
            }
        </ol>
    }
</div>

@code {
    [Parameter] public int Id { get; set; }
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private Recipe? _recipe;

    protected override void OnInitialized()
    {
        _recipe = RecipeService.GetRecipeById(Id);
    }

    private void HandleRating(int stars)
    {
        RecipeService.AddRating(Id, stars);
        _recipe = RecipeService.GetRecipeById(Id);
    }
}

@page "/submit"
@using RecipeCommunity.Models
@using RecipeCommunity.Services
@rendermode InteractiveServer

<PageTitle>Submit a Recipe</PageTitle>

<div class="container">
    <h1>Submit a Recipe</h1>
    <p>Share your favorite recipe with the community!</p>

    @if (_submitted)
    {
        <div class="alert alert-success">
            <h4>Recipe submitted!</h4>
            <p>Your recipe "<strong>@_submission.Title</strong>" has been added. <a href="/">Browse recipes</a></p>
        </div>
    }
    else
    {
        <EditForm Model="_submission" OnValidSubmit="HandleSubmit" FormName="recipeForm">
            <DataAnnotationsValidator />

            <div class="mb-3">
                <label for="title" class="form-label">Recipe Title</label>
                <InputText id="title" @bind-Value="_submission.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
            </div>

            <div class="mb-3">
                <label for="category" class="form-label">Category</label>
                <InputSelect id="category" @bind-Value="_submission.Category" class="form-select">
                    <option value="">-- Select a category --</option>
                    @foreach (var cat in _categories)
                    {
                        <option value="@cat.Name">@cat.Name</option>
                    }
                </InputSelect>
            </div>

            <div class="mb-3">
                <label for="ingredients" class="form-label">Ingredients (one per line)</label>
                <InputTextArea id="ingredients" @bind-Value="_submission.Ingredients" class="form-control" rows="6"
                    placeholder="2 cups flour&#10;1 cup sugar&#10;3 large apples" />
            </div>

            <div class="mb-3">
                <label for="steps" class="form-label">Steps (one per line)</label>
                <InputTextArea id="steps" @bind-Value="_submission.Steps" class="form-control" rows="6"
                    placeholder="Preheat oven to 350°F.&#10;Mix dry ingredients.&#10;Add wet ingredients." />
            </div>

            <button type="submit" class="btn btn-success btn-lg">Submit Recipe</button>
        </EditForm>
    }
</div>

@code {
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private RecipeSubmission _submission = new();
    private List<RecipeCategory> _categories = [];
    private bool _submitted;

    protected override void OnInitialized()
    {
        _categories = RecipeService.GetCategories();
    }

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(_submission.Title)) return;
        RecipeService.SubmitRecipe(_submission);
        _submitted = true;
    }
}

